catalog_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {
   if (isLoading || newValue == '') {
      return;
   }

    var mrvsValue = g_form.getValue('IO:94cecc8347c947d0516b5ac5316d43cf'); 
	console.log(mrvsValue);
    if (!mrvsValue) return;


    var rows = JSON.parse(mrvsValue);


    var currentRowIndex = -1;
    var match = newValue.match(/\[(\d+)\]/); // الصيغة غالباً medicines_order[0].medicine_name
    if (match) {
        currentRowIndex = parseInt(match[1], 10);
    } else {
        // طريقة بديلة: نبحث عن الصف اللي فيه oldValue (القيمة القديمة)
        for (var i = 0; i < rows.length; i++) {
            if (rows[i].medicine_name === oldValue) {
                currentRowIndex = i;
                break;
            }
        }
    }

    // 4. نفحص التكرار (نتخطى الصف الحالي)
    var isDuplicate = false;
    for (var i = 0; i < rows.length; i++) {
        if (i === currentRowIndex) continue;
        if (rows[i].medicine_name === newValue) {
            isDuplicate = true;
            break;
        }
    }

    // 5. إذا وجد تكرار، نمنع التغيير ونعرض رسالة
    if (isDuplicate) {
        g_form.showFieldMsg(control.name, '❌ This medicine is already in your order. Please edit the quantity in the existing row.', 'error');
        g_form.setValue(control.name, oldValue);
        return;
    }

    // 6. إخفاء أي رسالة خطأ سابقة
    g_form.hideFieldMsg(control.name);
}
